import{_ as o,c as t,o as r,ae as l}from"./chunks/framework.B7Y1jjX-.js";const m=JSON.parse('{"title":"前端模块化","description":"","frontmatter":{},"headers":[],"relativePath":"notes/前端/三件套/JS/前端模块化.md","filePath":"notes/前端/三件套/JS/前端模块化.md"}'),i={name:"notes/前端/三件套/JS/前端模块化.md"};function a(s,e,n,p,c,d){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="前端模块化" tabindex="-1">前端模块化 <a class="header-anchor" href="#前端模块化" aria-label="Permalink to &quot;前端模块化&quot;">​</a></h1><p>在<code>vite(rollup)</code>的打包配置里有一个<code>format</code>的选项，可以指定最终打包产物的格式，默认情况下是<code>ES module</code>，但是不同的场景可能会有所区别，本文就想通过这个来讲讲前端模块化。</p><h2 id="iife" tabindex="-1">IIFE <a class="header-anchor" href="#iife" aria-label="Permalink to &quot;IIFE&quot;">​</a></h2><p>自执行函数</p><blockquote><p>英文全称：immediately invoked function expressions</p></blockquote><p><strong>适用场景</strong> 浏览器中带有<code>&lt;script&gt;</code>标签包裹的代码块，简单来说就是普通的业务应用都可，没啥兼容问题</p><p><strong>优点</strong></p><ul><li>函数作用域避免了全局变量的污染 iife也算是比较早期的模块化方案了，只需对外暴露一个全局变量，最知名的就是<code>jQuery</code></li></ul><h2 id="cjs" tabindex="-1">CJS <a class="header-anchor" href="#cjs" aria-label="Permalink to &quot;CJS&quot;">​</a></h2><p>真正的模块化解决方案，最早从Node应用开始</p><blockquote><p>全称：CommonJS</p></blockquote><p><strong>关键词：module，exports，global，require</strong></p><p><strong>特点</strong></p><ul><li>模块加载<code>require</code>就是代码执行</li><li>所有代码运行在模块作用域中，不污染全局</li><li>模块可以多次加载，但是只在第一次加载运行，后面是缓存</li></ul><p><strong>适用场景</strong> Nodejs，浏览器端需要用其他打包工具支持</p><h2 id="amd" tabindex="-1">AMD <a class="header-anchor" href="#amd" aria-label="Permalink to &quot;AMD&quot;">​</a></h2><p>异步模块定义</p><blockquote><p>全拼：Asynchronous module definition</p></blockquote><p>amd可以理解是CommonJs在浏览器端的解决方案，cjs在服务端是<strong>同步加载</strong>依赖代码的，因为服务端都是本地磁盘读取文件，没有网络开销，速度很快，浏览器端要是也这么干，很有可能因为依赖在远程，因网络时间开销而导致出现“假死”，所以浏览器端采用<strong>异步加载</strong>模块的方式。</p><p><strong>关键词</strong>：require，define</p><p>require的第一个参数是需要异步加载的依赖列表，第二个是模块异步加载后的执行代码，define第一个参数是模块的依赖模块，第二个是模块代码</p><p><strong>优点</strong></p><ul><li>体积更小，代码<strong>按需加载</strong></li><li>不堵塞js线程运行</li></ul><h2 id="umd" tabindex="-1">UMD <a class="header-anchor" href="#umd" aria-label="Permalink to &quot;UMD&quot;">​</a></h2><p>联合模块定义</p><blockquote><p>全拼：Universal Module Definition</p></blockquote><p>准确来说并不是一个独立的模块标准，而是集合了cjs，amd，iife等一体的打包模式，会自动判断当前可用环境。</p><p><strong>优点</strong>：</p><ul><li>一套代码，多端使用，模块化兼容性好</li></ul><p>一般会在webpack中成为备用模块</p><h2 id="esm" tabindex="-1">ESM <a class="header-anchor" href="#esm" aria-label="Permalink to &quot;ESM&quot;">​</a></h2><p>ES6标准中的模块规则，一统浏览器和服务端标准的解决方案</p><blockquote><p>全拼：ES6 Module</p></blockquote><p><strong>关键字</strong>：import，export</p><p><strong>适用场景</strong>： 结合其他打包工具（webpack）使用或浏览器<code>&lt;script type=&quot;module&quot;&gt;</code>标签包裹</p><p><strong>特点</strong>：</p><ul><li>浏览器端会异步加载，延续AMD的优势，但利用了浏览器原生的解析能力，代码体积更小</li><li>模块内自动采用<strong>严格模式</strong></li><li>模块中的this指向并不是window或global，而是<code>undefined</code></li></ul><p>和cjs的三个差异：</p><ul><li>cjs 模块输出的是一个值的拷贝（浅拷贝），esm输出的是值的引用。</li><li>cjs 模块是运行时加载，esm是编译时输出接口。</li><li>cjs同步加载模块，esm异步加载，有一个独立的模块依赖的解析阶段。</li></ul><p>在cjs中，如果多个地方都用了同一个模块，对这个模块进行修改，其实不会有影响，但是在esm中，如果你用incCounter修改了counter值，其他业务模块调用counter的时候就会有变化</p><p>原因是esm中模块加载的时候还没完全去取值，实际业务代码执行到了才会去拿真正的值，import的时候只是建了个具体地址，留着后面调用时候方便。</p>',41)])])}const g=o(i,[["render",a]]);export{m as __pageData,g as default};
